sql:
SELECT product_id, brand, style, price
FROM bra_products
WHERE price IS NULL;

SELECT oh.product_id, COUNT(*) AS total_orders
FROM order_history AS oh
GROUP BY oh.product_id;

external_knowledge:
Existing bra types refer to bra types present in the bra_types table; 
Details of bra products include product IDs, brands, and styles; 
Preferences are stored in the customer_preferences table.

sql:
SELECT customer_id, AVG(quantity) AS average_products_ordered
FROM order_history
GROUP BY customer_id;

SELECT AVG(julianday('now') - julianday(c.date_of_birth)) AS average_age
FROM customers c
JOIN order_history oh ON c.customer_id = oh.customer_id;

SELECT bp.style, AVG(bp.price) as average_price
FROM bra_products bp
GROUP BY bp.style;

SELECT bra_type, description
FROM bra_types
ORDER BY bra_type ASC;

SELECT product_id, brand, style, price
FROM bra_products
WHERE price = (
  SELECT MAX(price) FROM bra_products
);

SELECT product_id
FROM bra_products
WHERE product_id NOT IN (
    SELECT product_id
    FROM order_history
);

SELECT COUNT(DISTINCT o.customer_id) AS unique_customers
FROM order_history o
JOIN recommendations r ON o.customer_id = r.customer_id AND o.product_id = r.product_id;

SELECT AVG(bp.price) AS average_price
FROM customer_preferences cp
JOIN bra_products bp ON cp.bra_type_id = bp.type_id;
